    {galdera:{eu:"Zer protokolo eta portu erabiltzen ditu DHCP-ak?",es:"¿Qué protocolo y puertos usa el DHCP?"}, aukerak:[{eu:"UDP, 67 eta 68 portuak",es:"UDP, puertos 67 y 68"},{eu:"TCP, 53 portua",es:"TCP, puerto 53"},{eu:"TCP, 80 portua",es:"TCP, puerto 80"}], zuzena:0, azalpena:{eu:"DHCP UDP-z doa: 67 zerbitzarian, 68 bezeroan.",es:"DHCP va por UDP: 67 en el servidor, 68 en el cliente."}},
    {galdera:{eu:"Zergatik deskonektatzen da kablea aulan zure DHCP abiarazi aurretik?",es:"¿Por qué se desconecta el cable del aula antes de arrancar tu DHCP?"}, aukerak:[{eu:"Energia aurrezteko",es:"Para ahorrar energía"},{eu:"Beste DHCP-ekin lehiatu ez dadin",es:"Para no competir con otros DHCP"},{eu:"DHCP-ak sarerik gabe behar duelako",es:"Porque el DHCP necesita estar sin red"}], zuzena:1, azalpena:{eu:"DHCP bat baino gehiago LAN berean talka egiten dute.",es:"Más de un DHCP en la misma LAN chocan."}},
    {galdera:{eu:"Zertarako balio du `host` deklarazio batek?",es:"¿Para qué sirve una declaración `host`?"}, aukerak:[{eu:"Ekipoa blokeatzeko",es:"Para bloquear el equipo"},{eu:"IP aleatorioa emateko",es:"Para dar IP aleatoria"},{eu:"MAC horrek beti IP bera jasotzeko (erreserba)",es:"Para que esa MAC reciba siempre la misma IP (reserva)"}], zuzena:2, azalpena:{eu:"MAC bat IP finko batera lotzen du.",es:"Asocia una MAC a una IP fija."}}
